// Pre-check and prepare data for Claude OCR
const body = $input.first().json.body || $input.first().json;

const filename = body.filename || 'unknown.jpg';
const minioPath = body.minio_path || '';
const emailFrom = body.email_from || '';
const emailSubject = body.email_subject || '';
const source = body.source || 'manual';
const mimeType = body.mime_type || 'image/jpeg';
const base64Data = body.base64_data || '';

// Generate unique invoice processing ID
const processingId = 'inv_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);

return [{
  json: {
    processing_id: processingId,
    filename: filename,
    minio_path: minioPath,
    email_from: emailFrom,
    email_subject: emailSubject,
    source: source,
    mime_type: mimeType,
    base64_data: base64Data,
    has_base64: base64Data.length > 0
  }
}];

