// Parse Claude response and extract invoice data
const preCheckData = $('Fraud Pre-check').first().json;
const claudeResponse = $input.first().json;

let invoiceData = {};
let parseError = null;

try {
  // Claude returns content[0].text
  const content = claudeResponse.content;
  if (content && content[0] && content[0].text) {
    let rawText = content[0].text.trim();
    // Remove markdown code blocks if present
    rawText = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    invoiceData = JSON.parse(rawText);
  } else if (claudeResponse.error) {
    parseError = claudeResponse.error.message || 'Claude API error';
    // Fallback data when Claude fails
    invoiceData = {
      vendor_name: 'Unknown',
      invoice_number: 'UNKNOWN-' + Date.now(),
      invoice_date: new Date().toISOString().split('T')[0],
      iban: '',
      bic: '',
      total_amount: 0,
      vat_amount: 0,
      vat_rate: 0,
      currency: 'EUR',
      invoice_type: 'supplier'
    };
  }
} catch (e) {
  parseError = 'JSON parse error: ' + e.message;
  invoiceData = {
    vendor_name: 'Parse Error',
    invoice_number: 'ERR-' + Date.now(),
    invoice_date: new Date().toISOString().split('T')[0],
    iban: '',
    bic: '',
    total_amount: 0,
    vat_amount: 0,
    vat_rate: 0,
    currency: 'EUR',
    invoice_type: 'supplier'
  };
}

// IBAN Fraud Check Logic
const iban = (invoiceData.iban || '').trim().replace(/\s/g, '');
let fraudStatus = 'pending';
let fraudReason = '';

if (!iban || iban === '') {
  fraudStatus = 'no_iban';
  fraudReason = 'No IBAN found in invoice';
} else if (iban.toUpperCase().startsWith('DE')) {
  fraudStatus = 'approved';
  fraudReason = 'German IBAN - OK';
} else {
  fraudStatus = 'suspicious';
  fraudReason = 'Non-German IBAN detected: ' + iban;
}

return [{
  json: {
    processing_id: preCheckData.processing_id,
    filename: preCheckData.filename,
    minio_path: preCheckData.minio_path,
    email_from: preCheckData.email_from,
    email_subject: preCheckData.email_subject,
    source: preCheckData.source,
    // Invoice data from Claude
    vendor_name: invoiceData.vendor_name || '',
    vendor_address: invoiceData.vendor_address || '',
    vendor_tax_id: invoiceData.vendor_tax_id || '',
    invoice_number: invoiceData.invoice_number || '',
    invoice_date: invoiceData.invoice_date || null,
    due_date: invoiceData.due_date || null,
    iban: iban,
    bic: invoiceData.bic || '',
    total_amount: parseFloat(invoiceData.total_amount) || 0,
    vat_amount: parseFloat(invoiceData.vat_amount) || 0,
    vat_rate: parseFloat(invoiceData.vat_rate) || 0,
    currency: invoiceData.currency || 'EUR',
    invoice_type: invoiceData.invoice_type || 'supplier',
    line_items: JSON.stringify(invoiceData.line_items || []),
    // Fraud check result
    fraud_status: fraudStatus,
    fraud_reason: fraudReason,
    parse_error: parseError,
    raw_ocr_data: JSON.stringify(invoiceData)
  }
}];

